import urllib.parse
import urllib.request
import json

def get_llm_response(prompt):
    url = "http://localhost:8000/api/chat"
    data = {
        "model": "ail-coder:7b-v3",
        "messages": [{"role": "user", "content": prompt}],
        "stream": False
    }
    data = json.dumps(data).encode("utf-8")
    req = urllib.request.Request(url, data, headers={"Content-Type": "application/json"})
    with urllib.request.urlopen(req) as f:
        response = json.loads(f.read().decode("utf-8"))
    return response["message"]["content"]

def count_char_freq(text):
    freq = {}
    for char in text:
        if char in freq:
            freq[char] += 1
        else:
            freq[char] = 1
    return freq

def describe_pattern(freq):
    sorted_freq = sorted(freq.items(), key=lambda x: x[1], reverse=True)
    pattern = []
    for char, count in sorted_freq:
        pattern.append(f"{char}: {count}")
    return ", ".join(pattern)

text = "hello world"
freq = count_char_freq(text)
pattern = describe_pattern(freq)
prompt = f"Describe the pattern in the character frequencies: {pattern}"
description = get_llm_response(prompt)
print(description)

