fn fibonacci(n: Number) -> Number {
    if n <= 1 { return n }
    return fibonacci(n - 1) + fibonacci(n - 2)
}

fn fibonacci_sequence(limit: Number) -> [Number] {
    results = []
    for i in range(0, limit) {
        results = append(results, fibonacci(i))
    }
    return results
}

fn golden_ratio_approx(sequence: [Number]) -> Number {
    return round(sequence[limit - 1] / sequence[limit - 2], 2)
}

entry main(limit: Number) {
    sequence = fibonacci_sequence(limit)
    ratio = golden_ratio_approx(sequence)
    return join([to_text(sequence), " (approx golden ratio: ", to_text(ratio), ")"], "")
}

